import{_ as a,o as e,c as i,ag as d}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"Day1 - 重新认识英语","description":"英语学习第一天，目标是6个月能够日常交流。开始词汇积累和听力练习。","frontmatter":{"title":"Day1 - 重新认识英语","description":"英语学习第一天，目标是6个月能够日常交流。开始词汇积累和听力练习。","keywords":"英语学习, 词汇积累, 听力练习, 新概念英语"},"headers":[],"relativePath":"learn/english/day1.md","filePath":"learn/english/day1.md","lastUpdated":1774146119000}'),r={name:"learn/english/day1.md"};function l(s,t,n,o,h,c){return e(),i("div",null,[...t[0]||(t[0]=[d('<h1 id="day1-重新认识英语" tabindex="-1"><a class="header-anchor" href="#day1-重新认识英语">¶</a> Day1 - 重新认识英语</h1><blockquote><p>种一棵树最好的时间是十年前，其次是现在</p></blockquote><h2 id="🎯-今日目标" tabindex="-1"><a class="header-anchor" href="#🎯-今日目标">¶</a> 🎯 今日目标</h2><ul><li>[x] 明确学习目标</li><li>[x] 制定学习计划</li><li>[x] 开始词汇积累</li><li>[x] 开始听力练习</li></ul><h2 id="📝-学习内容" tabindex="-1"><a class="header-anchor" href="#📝-学习内容">¶</a> 📝 学习内容</h2><h3 id="_1-为什么要学英语" tabindex="-1"><a class="header-anchor" href="#_1-为什么要学英语">¶</a> 1. 为什么要学英语？</h3><ul><li><strong>工作</strong>：看懂英文文档、技术博客</li><li><strong>生活</strong>：看美剧不用字幕</li><li><strong>交流</strong>：能够表达自己的想法</li><li><strong>视野</strong>：打开新世界的大门</li></ul><h3 id="_2-今日词汇-5个新词" tabindex="-1"><a class="header-anchor" href="#_2-今日词汇-5个新词">¶</a> 2. 今日词汇（5个新词）</h3><table tabindex="0"><thead><tr><th>单词</th><th>音标</th><th>含义</th><th>例句</th></tr></thead><tbody><tr><td>variable</td><td>/ˈveəriəbl/</td><td>变量</td><td>A variable stores data.</td></tr><tr><td>string</td><td>/strɪŋ/</td><td>字符串</td><td>This is a string.</td></tr><tr><td>integer</td><td>/ˈɪntɪdʒə/</td><td>整数</td><td>25 is an integer.</td></tr><tr><td>float</td><td>/fləʊt/</td><td>浮点数</td><td>3.14 is a float.</td></tr><tr><td>boolean</td><td>/ˈbuːliən/</td><td>布尔值</td><td>True is a boolean.</td></tr></tbody></table><h3 id="_3-今日听力" tabindex="-1"><a class="header-anchor" href="#_3-今日听力">¶</a> 3. 今日听力</h3><p><strong>材料</strong>：新概念英语第一册 Lesson 1</p><p><strong>内容</strong>：</p><blockquote><p>Excuse me. Yes? Is this your handbag? Pardon? Is this your handbag? Yes, it is. Thank you very much.</p></blockquote><h3 id="_4-今日口语" tabindex="-1"><a class="header-anchor" href="#_4-今日口语">¶</a> 4. 今日口语</h3><p><strong>跟读</strong>：新概念英语 Lesson 1（5遍） <strong>重点</strong>：注意连读和语调</p><h3 id="_5-今日语法" tabindex="-1"><a class="header-anchor" href="#_5-今日语法">¶</a> 5. 今日语法</h3><p><strong>be动词的用法</strong>：</p><ul><li>I am = I&#39;m</li><li>you are = you&#39;re</li><li>he is = he&#39;s</li><li>she is = she&#39;s</li><li>it is = it&#39;s</li></ul><p><strong>否定句</strong>：</p><ul><li>I am not = I&#39;m not</li><li>you are not = you aren&#39;t</li></ul><p><strong>疑问句</strong>：</p><ul><li>Are you a student? Yes, I am. / No, I&#39;m not.</li><li>Is this your bag? Yes, it is. / No, it isn&#39;t.</li></ul><h2 id="📚-今日学习资源" tabindex="-1"><a class="header-anchor" href="#📚-今日学习资源">¶</a> 📚 今日学习资源</h2><table tabindex="0"><thead><tr><th>资源</th><th>用途</th><th>链接</th></tr></thead><tbody><tr><td>新概念英语1</td><td>课文+听力</td><td>每日英语听力App</td></tr><tr><td>Anki</td><td>单词记忆</td><td>ankiweb.net</td></tr><tr><td>BBC Learning English</td><td>听力练习</td><td>bbc.co.uk/learningenglish</td></tr></tbody></table><h2 id="⏱️-今日耗时" tabindex="-1"><a class="header-anchor" href="#⏱️-今日耗时">¶</a> ⏱️ 今日耗时</h2><ul><li>词汇：15分钟（新学5词 + 复习10词）</li><li>听力：20分钟（新概念1 Lesson 1）</li><li>口语：10分钟（跟读5遍）</li><li>语法：15分钟（be动词）</li></ul><p><strong>总计：60分钟</strong></p><h2 id="✅-今日总结" tabindex="-1"><a class="header-anchor" href="#✅-今日总结">¶</a> ✅ 今日总结</h2><ul><li>制定了6个月学习计划 ✓</li><li>学会了5个编程相关英语单词 ✓</li><li>完成了新概念英语Lesson 1 ✓</li><li>理解了be动词用法 ✓</li></ul><h2 id="📅-明日计划" tabindex="-1"><a class="header-anchor" href="#📅-明日计划">¶</a> 📅 明日计划</h2><ul><li>复习今天学的5个单词</li><li>学习新概念 Lesson 2</li><li>积累5个新单词</li><li>听力30分钟</li></ul><hr><blockquote><p><strong>坚持就是胜利！</strong> 每天1小时，6个月后见证奇迹</p></blockquote>',33)])])}const u=a(r,[["render",l]]);export{g as __pageData,u as default};
